mapper.insert:
INSERT INTO WAREHOUSE_STOCK_LOG (
      LOG_ID
    , ACTION_TYPE
    , ACTION_DATE
    , WORKER_ID
    , STOCK_ID
    , UNIQUE_NO
    , ITEM_NAME
    , QTY
    , GROSS_WEIGHT
    , WAREHOUSE_ID
    , DEL_YN
    , POSITION_AREA
    , DECL_NO
    , MEM_ID
    , OUT_DATE
    , REP_NAME
    , CONT_NO
) VALUES (
      STOCK_LOG_SEQ.NEXTVAL
    , #{actionType}
    , SYSDATE
    , #{workerId}
    , #{stockId}
    , #{uniqueNo}
    , #{itemName}
    , #{qty}
    , #{grossWeight}
    , #{warehouseId}
    , 'N'
    , #{positionArea}
    , #{declNo}
    , #{memId}
    , #{outDate}
    , #{repName}
    , #{contNo}
)
